// auth_state.dart
enum AuthStatus { unknown, authenticated, unauthenticated }

class AuthState extends Equatable {
  final AuthStatus status;
  final User? user;
  final String? error;

  const AuthState({this.status = AuthStatus.unknown, this.user, this.error});

  AuthState copyWith({AuthStatus? status, User? user, String? error}) {
    return AuthState(
      status: status ?? this.status,
      user: user ?? this.user,
      error: error ?? this.error,
    );
  }

  @override
  List<Object?> get props => [status, user, error];
}

// auth_event.dart
abstract class AuthEvent extends Equatable { ... }
class AppStarted extends AuthEvent {}
class LoggedIn extends AuthEvent { final User user; ... }
class LoggedOut extends AuthEvent {}

// auth_bloc.dart
class AuthBloc extends Bloc<AuthEvent, AuthState> {
  AuthBloc() : super(const AuthState()) {
    on<AppStarted>(_onAppStarted);
    on<LoggedIn>(_onLoggedIn);
    on<LoggedOut>(_onLoggedOut);
  }
  // ... implementation
}

class AppRouter extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    return BlocListener<AuthBloc, AuthState>(
      listener: (context, state) {
        if (state.status == AuthStatus.authenticated) {
          // User is logged in, navigate to home if currently on login/splash
          if (ModalRoute.of(context)?.settings.name == '/login') {
            Navigator.pushReplacementNamed(context, '/home');
          }
        } else if (state.status == AuthStatus.unauthenticated) {
          // User is logged out, navigate to login
          Navigator.pushReplacementNamed(context, '/login');
        }
      },
      child: MaterialApp(
        initialRoute: '/splash',
        routes: {
          '/splash': (context) => SplashPage(),
          '/login': (context) => LoginPage(),
          '/home': (context) => HomePage(),
          '/profile': (context) => ProfilePage(),
        },
      ),
    );
  }
}

class ProtectedRoute extends StatelessWidget {
  final Widget child;
  const ProtectedRoute({required this.child});

  @override
  Widget build(BuildContext context) {
    final authState = context.watch<AuthBloc>().state;
    if (authState.status == AuthStatus.authenticated) {
      return child;
    } else {
      // Redirect to login
      WidgetsBinding.instance.addPostFrameCallback((_) {
        Navigator.pushReplacementNamed(context, '/login');
      });
      return const Scaffold(body: Center(child: CircularProgressIndicator()));
    }
  }
}

// Usage in routes:
'/profile': (context) => ProtectedRoute(child: ProfilePage()),

import 'package:go_router/go_router.dart';

final router = GoRouter(
  initialLocation: '/',
  redirect: (context, state) {
    final authState = context.read<AuthBloc>().state;
    final isLoggedIn = authState.status == AuthStatus.authenticated;
    final isGoingToLogin = state.matchedLocation == '/login';

    if (!isLoggedIn && !isGoingToLogin) {
      return '/login';
    }
    if (isLoggedIn && isGoingToLogin) {
      return '/';
    }
    return null;
  },
  routes: [
    GoRoute(
      path: '/',
      builder: (context, state) => const HomePage(),
    ),
    GoRoute(
      path: '/login',
      builder: (context, state) => const LoginPage(),
    ),
    GoRoute(
      path: '/profile',
      builder: (context, state) => const ProfilePage(),
    ),
  ],
);

// In main:
runApp(BlocProvider(
  create: (_) => AuthBloc()..add(AppStarted()),
  child: MaterialApp.router(
    routerConfig: router,
  ),
));

class RoleGuard extends StatelessWidget {
  final List<String> allowedRoles;
  final Widget child;
  final Widget? forbiddenWidget;

  const RoleGuard({
    required this.allowedRoles,
    required this.child,
    this.forbiddenWidget,
  });

  @override
  Widget build(BuildContext context) {
    final authState = context.watch<AuthBloc>().state;
    if (authState.status == AuthStatus.authenticated &&
        allowedRoles.contains(authState.user?.role)) {
      return child;
    }
    return forbiddenWidget ??
        const Scaffold(
          body: Center(child: Text('Access Denied')),
        );
  }
}

// Usage in GoRouter:
GoRoute(
  path: '/admin',
  builder: (context, state) => RoleGuard(
    allowedRoles: ['admin'],
    child: AdminPage(),
  ),
);

