import 'package:flutter/material.dart';
import 'package:flutter_bloc/flutter_bloc.dart';
import 'package:equatable/equatable.dart';

void main() => runApp(MyApp());

// ---------- Auth BLoC ----------
enum AuthStatus { unknown, authenticated, unauthenticated }

class AuthState extends Equatable {
  final AuthStatus status;
  final String? userName;
  final String? role;
  final String? error;

  const AuthState({
    this.status = AuthStatus.unknown,
    this.userName,
    this.role,
    this.error,
  });

  AuthState copyWith({
    AuthStatus? status,
    String? userName,
    String? role,
    String? error,
  }) {
    return AuthState(
      status: status ?? this.status,
      userName: userName ?? this.userName,
      role: role ?? this.role,
      error: error ?? this.error,
    );
  }

  @override
  List<Object?> get props => [status, userName, role, error];
}

abstract class AuthEvent extends Equatable {
  const AuthEvent();
  @override List<Object?> get props => [];
}

class AppStarted extends AuthEvent {}
class LoginRequested extends AuthEvent {
  final String username;
  final String password;
  const LoginRequested(this.username, this.password);
}
class LogoutRequested extends AuthEvent {}

class AuthBloc extends Bloc<AuthEvent, AuthState> {
  AuthBloc() : super(const AuthState()) {
    on<AppStarted>(_onAppStarted);
    on<LoginRequested>(_onLoginRequested);
    on<LogoutRequested>(_onLogoutRequested);
  }

  void _onAppStarted(AppStarted event, Emitter<AuthState> emit) {
    // Check for persisted auth (simulate)
    emit(state.copyWith(status: AuthStatus.unauthenticated));
  }

  Future<void> _onLoginRequested(LoginRequested event, Emitter<AuthState> emit) async {
    emit(state.copyWith(status: AuthStatus.unknown, error: null));
    await Future.delayed(Duration(seconds: 1));
    if (event.username == 'admin' && event.password == 'admin') {
      emit(state.copyWith(
        status: AuthStatus.authenticated,
        userName: event.username,
        role: 'admin',
      ));
    } else if (event.username == 'user' && event.password == 'user') {
      emit(state.copyWith(
        status: AuthStatus.authenticated,
        userName: event.username,
        role: 'user',
      ));
    } else {
      emit(state.copyWith(
        status: AuthStatus.unauthenticated,
        error: 'Invalid credentials',
      ));
    }
  }

  void _onLogoutRequested(LogoutRequested event, Emitter<AuthState> emit) {
    emit(const AuthState(status: AuthStatus.unauthenticated));
  }
}

// ---------- Navigation Guard with BlocListener ----------
class AppRouter extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    return BlocListener<AuthBloc, AuthState>(
      listener: (context, state) {
        if (state.status == AuthStatus.unauthenticated) {
          // Only navigate to login if not already there
          final currentRoute = ModalRoute.of(context)?.settings.name;
          if (currentRoute != '/login') {
            Navigator.pushReplacementNamed(context, '/login');
          }
        } else if (state.status == AuthStatus.authenticated) {
          final currentRoute = ModalRoute.of(context)?.settings.name;
          if (currentRoute == '/login') {
            Navigator.pushReplacementNamed(context, '/');
          }
        }
      },
      child: MaterialApp(
        initialRoute: '/splash',
        routes: {
          '/splash': (context) => SplashPage(),
          '/login': (context) => LoginPage(),
          '/': (context) => HomePage(),
          '/admin': (context) => AdminPage(),
        },
      ),
    );
  }
}

// ---------- UI Pages ----------
class SplashPage extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    // Simulate loading
    Future.delayed(Duration(milliseconds: 500), () {
      if (context.mounted) {
        Navigator.pushReplacementNamed(context, '/login');
      }
    });
    return Scaffold(body: Center(child: CircularProgressIndicator()));
  }
}

class LoginPage extends StatefulWidget {
  @override
  _LoginPageState createState() => _LoginPageState();
}

class _LoginPageState extends State<LoginPage> {
  final TextEditingController userController = TextEditingController();
  final TextEditingController passController = TextEditingController();

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(title: Text('Login')),
      body: Padding(
        padding: const EdgeInsets.all(16.0),
        child: Column(
          mainAxisAlignment: MainAxisAlignment.center,
          children: [
            TextField(controller: userController, decoration: InputDecoration(labelText: 'Username')),
            TextField(controller: passController, obscureText: true, decoration: InputDecoration(labelText: 'Password')),
            SizedBox(height: 20),
            BlocConsumer<AuthBloc, AuthState>(
              listener: (context, state) {
                if (state.error != null) {
                  ScaffoldMessenger.of(context).showSnackBar(
                    SnackBar(content: Text(state.error!)),
                  );
                }
              },
              builder: (context, state) {
                if (state.status == AuthStatus.unknown) {
                  return CircularProgressIndicator();
                }
                return ElevatedButton(
                  onPressed: () {
                    context.read<AuthBloc>().add(LoginRequested(
                      userController.text,
                      passController.text,
                    ));
                  },
                  child: Text('Login'),
                );
              },
            ),
            SizedBox(height: 20),
            Text('Demo: admin/admin or user/user'),
          ],
        ),
      ),
    );
  }
}

class HomePage extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    final authState = context.watch<AuthBloc>().state;
    return Scaffold(
      appBar: AppBar(
        title: Text('Home'),
        actions: [
          IconButton(
            icon: Icon(Icons.logout),
            onPressed: () => context.read<AuthBloc>().add(LogoutRequested()),
          ),
        ],
      ),
      body: Center(
        child: Column(
          mainAxisAlignment: MainAxisAlignment.center,
          children: [
            Text('Welcome, ${authState.userName}!'),
            Text('Role: ${authState.role}'),
            SizedBox(height: 20),
            if (authState.role == 'admin')
              ElevatedButton(
                onPressed: () => Navigator.pushNamed(context, '/admin'),
                child: Text('Go to Admin Page'),
              ),
          ],
        ),
      ),
    );
  }
}

class AdminPage extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    final authState = context.watch<AuthBloc>().state;
    if (authState.role != 'admin') {
      return Scaffold(
        body: Center(child: Text('Access Denied')),
      );
    }
    return Scaffold(
      appBar: AppBar(title: Text('Admin Panel')),
      body: Center(child: Text('Secret admin content')),
    );
  }
}

// ---------- Main ----------
class MyApp extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    return BlocProvider(
      create: (_) => AuthBloc()..add(AppStarted()),
      child: AppRouter(),
    );
  }
}
